type JournalMentorLibraryRow = {
  sourceType?: "youtube" | "journal";
  journalMentorReflectionsStatus?: "pending" | "ready" | "failed";
  journalMentorReflections?: { figureId: string; figureName: string; reflection: string }[];
};

function hueFromFigureId(id: string): number {
  let h = 0;
  for (let i = 0; i < id.length; i++) h = (h * 31 + id.charCodeAt(i)) >>> 0;
  return h % 360;
}

function figureInitials(name: string): string {
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "?";
  if (parts.length === 1) return parts[0]!.slice(0, 2).toUpperCase();
  return (parts[0]![0] + parts[parts.length - 1]![0]).toUpperCase();
}

function MentorAvatarBubble({
  figureId,
  figureName,
  size,
  showDot = false,
  interactive = false,
  selected = false,
  onClick,
}: {
  figureId: string;
  figureName: string;
  size: number;
  showDot?: boolean;
  interactive?: boolean;
  selected?: boolean;
  onClick?: () => void;
}) {
  const hue = hueFromFigureId(figureId);
  const initials = figureInitials(figureName);
  const fontSize = Math.max(9, Math.round(size * 0.32));
  const circleClass = `rounded-full border-2 border-amber-400/40 dark:border-amber-500/45 flex items-center justify-center shrink-0 shadow-sm transition-transform ${
    interactive ? "cursor-pointer hover:scale-105 focus:outline-none focus-visible:ring-2 focus-visible:ring-accent/80 focus-visible:ring-offset-2 focus-visible:ring-offset-background" : ""
  } ${selected ? "ring-2 ring-accent dark:ring-accent ring-offset-2 ring-offset-neutral-50 dark:ring-offset-neutral-900" : ""}`;
  const circleStyle = {
    width: size,
    height: size,
    background: `linear-gradient(145deg, hsl(${hue}, 38%, 40%) 0%, hsl(${(hue + 28) % 360}, 36%, 30%) 100%)`,
  } as const;
  const inner = (
    <span className="text-white font-semibold leading-none" style={{ fontSize }}>
      {initials}
    </span>
  );
  return (
    <div className="flex flex-col items-center gap-0.5">
      {interactive && onClick ? (
        <button
          type="button"
          onClick={onClick}
          className={circleClass}
          style={circleStyle}
          title={figureName}
          aria-label={`Open reflection from ${figureName}`}
          aria-expanded={selected}
        >
          {inner}
        </button>
      ) : (
        <div className={circleClass} style={circleStyle} title={figureName}>
          {inner}
        </div>
      )}
      {showDot ? (
        <span className="w-1 h-1 rounded-full bg-amber-500/55 dark:bg-amber-400/50 shrink-0" aria-hidden />
      ) : null}
    </div>
  );
}

function MentorPendingBubbleSkeleton({ size, showDot = false }: { size: number; showDot?: boolean }) {
  return (
    <div className="flex flex-col items-center gap-0.5">
      <div
        className="rounded-full border-2 border-neutral-300/70 dark:border-neutral-600/80 bg-neutral-200/80 dark:bg-neutral-700/80 animate-pulse shrink-0"
        style={{ width: size, height: size }}
      />
      {showDot ? (
        <span className="w-1 h-1 rounded-full bg-neutral-400/45 shrink-0" aria-hidden />
      ) : null}
    </div>
  );
}

function JournalMentorListHint({
  row,
  language,
}: {
  row: JournalMentorLibraryRow;
  language: LanguageCode;
}) {
  if (row.sourceType !== "journal") return null;
  const ui = getUiTranslations(language);
  const status = row.journalMentorReflectionsStatus;
  const n = row.journalMentorReflections?.length ?? 0;
  const bubbleSize = 26;
  if (status === "pending") {
    return (
      <div className="mt-1.5 flex flex-col gap-1">
        <div className="flex items-center gap-1.5">
          {[0, 1, 2].map((i) => (
            <MentorPendingBubbleSkeleton key={i} size={bubbleSize} showDot={false} />
          ))}
        </div>
        <p className="text-[10px] text-neutral-500 dark:text-neutral-400 font-serif italic">
          {ui.journalMentorResponding}
        </p>
      </div>
    );
  }
  if (status === "ready" && n >= 1) {
    const refs = row.journalMentorReflections ?? [];
    return (
      <div className="mt-1.5 flex flex-col gap-1">
        <div className="flex items-center gap-1.5 flex-wrap">
          {refs.map((m) => (
            <MentorAvatarBubble
              key={m.figureId}
              figureId={m.figureId}
              figureName={m.figureName}
              size={bubbleSize}
              showDot={false}
            />
          ))}
        </div>
        <p className="text-[10px] text-neutral-600 dark:text-neutral-400 font-serif">
          {ui.journalMentorListReady.replace(/\{\{count\}\}/g, String(n))}
        </p>
      </div>
    );
  }
  if (status === "failed") {
    return (
      <div className="mt-1.5 flex flex-col gap-1">
        <div className="flex items-center gap-1.5 opacity-50">
          {[0, 1, 2].map((i) => (
            <div
              key={i}
              className="rounded-full border-2 border-neutral-300/60 dark:border-neutral-600 shrink-0 bg-neutral-100 dark:bg-neutral-800"
              style={{ width: bubbleSize, height: bubbleSize }}
            />
          ))}
        </div>
        <p className="text-[10px] text-amber-800/90 dark:text-amber-400/85 font-serif">
          {ui.journalMentorFailed}
        </p>
      </div>
    );
  }
  if (status === undefined) {
    return (
      <p className="text-[10px] text-neutral-500 dark:text-neutral-500 mt-0.5">
        {ui.journalMentorListPromptGenerate}
      </p>
    );
  }
  return null;
}

interface Message {
  role: "user" | "assistant";
  content: string;
  selectedContexts?: {
    mentalModels: RelevantContextItem[];
    longTermMemories: RelevantContextItem[];
    customConcepts: RelevantContextItem[];
    conceptGroups: RelevantContextItem[];
    perspectiveCards?: RelevantContextItem[];
  };
  perspectiveCard?: { name: string; prompt: string };
  /** 1:1 mentor intro chip */
  mentorOneOnOne?: { id: string; name: string };
  /** Second-order thinking intro chip */
  secondOrderThinking?: boolean;
  /** Plain vs citations (intro message before session is persisted); optional on history */
  secondOrderPlain?: boolean;
  mentorResponses?: Array<{ figureId: string; figureName: string; content: string }>;
  questions?: Array<{ prompt: string; options: string[] }>;
}

type ResponseVerbosity = "compact" | "detailed";

function processMessagesWithContext(msgs: Message[]): Message[] {
  return msgs.map((m) => {
    if (m.role === "assistant" && m.content) {
      let content = m.content;
      const { contentWithoutBlock: afterCtx, relevantContext } =
        parseRelevantContextBlock(content);
      content = afterCtx;
      const { contentWithoutBlock: afterMentor, mentorResponses } =
        parseMentorResponsesBlock(content);
      content = afterMentor;
      const { contentWithoutBlock: afterJournal } =
        parseJournalCheckpointBlock(content);
      const { contentWithoutBlock: afterQuestions, questions } =
        parseQuestionsBlock(afterJournal);
      return {
        ...m,
        content: afterQuestions,
        selectedContexts: relevantContext ?? undefined,
        mentorResponses: mentorResponses ?? undefined,
        questions: questions ?? undefined,
      };
    }
    return m;
  });
}

