function parseResponseVerbosity(value: unknown): ResponseVerbosity | null {
  return value === "compact" || value === "detailed" ? value : null;
}

const MENTOR_ONE_ON_ONE_PHRASES: Partial<
  Record<LanguageCode, { intro: (figureMention: string) => string; outro: string }>
> & { en: { intro: (figureMention: string) => string; outro: string } } = {
  en: {
    intro: (figureMention) =>
      `You're in a 1:1 with ${figureMention}. Replies will be grounded in their voice and ideas—share what's on your mind.`,
    outro: "What would you like to explore?",
  },
};

function buildMentorOneOnOneMessage(
  language: LanguageCode,
  figure: { id: string; name: string; description?: string }
): string {
  const phrases = MENTOR_ONE_ON_ONE_PHRASES[language] ?? MENTOR_ONE_ON_ONE_PHRASES.en;
  const figureMention = `[[figure:${figure.id}]]`;
  return `${phrases.intro(figureMention)}\n\n${phrases.outro}`;
}

const SECOND_ORDER_PHRASES: Partial<
  Record<LanguageCode, { intro: string; outro: string }>
> & { en: { intro: string; outro: string } } = {
  en: {
    intro:
      "You're in **metacognition** mode. We'll push past the first answer—consequences, incentives, and what happens next after that.",
    outro: "What's the situation or decision on your mind?",
  },
};

function buildSecondOrderMessage(language: LanguageCode): string {
  const phrases = SECOND_ORDER_PHRASES[language] ?? SECOND_ORDER_PHRASES.en;
  return `${phrases.intro}\n\n${phrases.outro}`;
}

function buildPerspectiveCardMessage(
  language: LanguageCode,
  prompt: string,
  figure?: { id: string; name: string }
): string {
  const phrases = PERSPECTIVE_CARD_PHRASES[language] ?? PERSPECTIVE_CARD_PHRASES.en;
  const intro = figure ? phrases.figureIntro(`[[figure:${figure.id}]]`) : phrases.intro;
  return `${intro}\n\n${prompt}\n\n${phrases.outro}`;
}

function MovingPills({
  onSelectStarter,
  language,
}: {
  onSelectStarter: (text: string) => void;
  language: LanguageCode;
}) {
  const [prefersReducedMotion, setPrefersReducedMotion] = useState(false);
  const [hoveredRow, setHoveredRow] = useState<number | null>(null);
  const starterRows = EXAMPLE_PILLS_BY_LANGUAGE[language] ?? EXAMPLE_PILLS_BY_LANGUAGE.en;
  const rows: CarouselStarterPill[][] = starterRows.map((row) =>
    row.map((label) => ({ label, type: "starter" as const }))
  );
  useEffect(() => {
    const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
    setPrefersReducedMotion(mq.matches);
    const handler = () => setPrefersReducedMotion(mq.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);
  const pillButtonClass =
    "inline-flex items-start gap-1.5 px-3 py-2 sm:px-4 sm:items-center rounded-full text-sm font-medium border transition-all duration-200 active:scale-95 bg-neutral-200/80 dark:bg-neutral-700/80 text-neutral-900 dark:text-neutral-100 border-neutral-300 dark:border-neutral-600 hover:bg-neutral-300 dark:hover:bg-neutral-600 whitespace-normal text-left max-w-full sm:whitespace-nowrap";

  return (
    <>
      {/* Narrow viewports: wrap so nothing overflows horizontally */}
      <div className="space-y-3 sm:hidden w-full min-w-0 max-w-full">
        {rows.map((row, rowIndex) => (
          <div
            key={rowIndex}
            className="flex flex-wrap gap-2 justify-center w-full min-w-0"
          >
            {row.map((pill, i) => (
              <button
                key={`${rowIndex}-m-${i}`}
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  playSelectionChime();
                  onSelectStarter(pill.label);
                }}
                className={pillButtonClass}
                aria-label={`Conversation starter: ${pill.label}`}
                title="Conversation starter"
              >
                <ChatBubbleIcon className="w-3.5 h-3.5 shrink-0 mt-0.5 sm:mt-0" />
                <span className="min-w-0 break-words">{pill.label}</span>
              </button>
            ))}
          </div>
        ))}
      </div>
      {/* sm+: horizontal marquee */}
      <div className="hidden sm:block space-y-4 overflow-hidden w-full min-w-0">
        {rows.map((row, rowIndex) => (
          <div
            key={rowIndex}
            className="flex overflow-hidden [mask-image:linear-gradient(to_right,transparent,black_10%,black_90%,transparent)]"
            onMouseEnter={() => setHoveredRow(rowIndex)}
            onMouseLeave={() => setHoveredRow(null)}
          >
            <div
              className={`flex gap-3 shrink-0 ${
                prefersReducedMotion
                  ? ""
                  : rowIndex % 2 === 0
                    ? "animate-marquee-left"
                    : "animate-marquee-right"
              } ${hoveredRow === rowIndex ? "marquee-paused" : ""}`}
              style={{ width: "max-content" }}
            >
              {[...row, ...row].map((pill, i) => (
                <button
                  key={`${rowIndex}-${i}`}
                  type="button"
                  onClick={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    playSelectionChime();
                    onSelectStarter(pill.label);
                  }}
                  className="inline-flex items-center gap-1.5 px-4 py-2 rounded-full text-sm font-medium border transition-all duration-200 active:scale-95 whitespace-nowrap bg-neutral-200/80 dark:bg-neutral-700/80 text-neutral-900 dark:text-neutral-100 border-neutral-300 dark:border-neutral-600 hover:bg-neutral-300 dark:hover:bg-neutral-600"
                  aria-label={`Conversation starter: ${pill.label}`}
                  title="Conversation starter"
                >
                  <ChatBubbleIcon className="w-3.5 h-3.5 shrink-0" />
                  {pill.label}
                </button>
              ))}
            </div>
          </div>
        ))}
      </div>
    </>
  );
}

type JournalEntryDateFields = {
  journalEntryDay?: number;
  journalEntryMonth?: number;
  journalEntryYear?: number;
  journalEntryHour?: number;
  journalEntryMinute?: number;
  createdAt?: string;
};

function formatJournalEntryListDate(t: JournalEntryDateFields): string {
  if (
    typeof t.journalEntryYear === "number" &&
    typeof t.journalEntryMonth === "number" &&
    typeof t.journalEntryDay === "number"
  ) {
    const hour = typeof t.journalEntryHour === "number" ? t.journalEntryHour : 0;
    const minute = typeof t.journalEntryMinute === "number" ? t.journalEntryMinute : 0;
    const d = new Date(t.journalEntryYear, t.journalEntryMonth - 1, t.journalEntryDay, hour, minute, 0, 0);
    return Number.isNaN(d.getTime())
      ? "—"
      : `${d.toLocaleDateString(undefined, { dateStyle: "medium" })} · ${d.toLocaleTimeString(undefined, {
          hour: "numeric",
          minute: "2-digit",
        })}`;
  }
  if (t.createdAt) {
    const d = new Date(t.createdAt);
    return Number.isNaN(d.getTime())
      ? "—"
      : `${d.toLocaleDateString(undefined, { dateStyle: "medium" })} · ${d.toLocaleTimeString(undefined, {
          hour: "numeric",
          minute: "2-digit",
        })}`;
  }
  return "—";
}

function getJournalCategoryLabel(
  category: "nutrition" | "exercise" | undefined
): string | null {
  if (category === "nutrition") return "Nutrition";
  if (category === "exercise") return "Exercise";
  return null;
}

function getJournalCategoryLabelWithRegular(
  category: "nutrition" | "exercise" | undefined
): "Regular" | "Nutrition" | "Exercise" {
  if (category === "nutrition") return "Nutrition";
  if (category === "exercise") return "Exercise";
  return "Regular";
}

function journalEntryDayKey(t: {
  journalEntryYear?: number;
  journalEntryMonth?: number;
  journalEntryDay?: number;
  createdAt?: string;
}): string | null {
  if (
    typeof t.journalEntryYear === "number" &&
    typeof t.journalEntryMonth === "number" &&
    typeof t.journalEntryDay === "number"
  ) {
    return toDayKey(new Date(t.journalEntryYear, t.journalEntryMonth - 1, t.journalEntryDay));
  }
  if (t.createdAt) {
    const d = new Date(t.createdAt);
    if (!Number.isNaN(d.getTime())) return toDayKey(d);
  }
  return null;
}

function journalEntryTimestamp(t: JournalEntryDateFields): number {
  if (
    typeof t.journalEntryYear === "number" &&
    typeof t.journalEntryMonth === "number" &&
    typeof t.journalEntryDay === "number"
  ) {
    const hour = typeof t.journalEntryHour === "number" ? t.journalEntryHour : 0;
    const minute = typeof t.journalEntryMinute === "number" ? t.journalEntryMinute : 0;
    const d = new Date(t.journalEntryYear, t.journalEntryMonth - 1, t.journalEntryDay, hour, minute, 0, 0);
    if (!Number.isNaN(d.getTime())) return d.getTime();
  }
  if (t.createdAt) {
    const d = new Date(t.createdAt);
    if (!Number.isNaN(d.getTime())) return d.getTime();
  }
  return 0;
}

