function summarizeNutritionFactsForDay(
  entries: Array<{
    sourceType?: "youtube" | "journal";
    transcriptText?: string;
    journalCategory?: "nutrition" | "exercise";
    journalEntryYear?: number;
    journalEntryMonth?: number;
    journalEntryDay?: number;
    createdAt?: string;
  }>,
  dayKey: string
): NutritionFactsDaySummary {
  const totals: Record<keyof NutritionFactsDaySummary, number> = {
    calories: 0,
    totalCarbohydratesGrams: 0,
    dietaryFiberGrams: 0,
    sugarGrams: 0,
    addedSugarsGrams: 0,
    sugarAlcoholsGrams: 0,
    netCarbsGrams: 0,
    proteinGrams: 0,
    totalFatGrams: 0,
    saturatedFatGrams: 0,
    transFatGrams: 0,
    polyunsaturatedFatGrams: 0,
    monounsaturatedFatGrams: 0,
    cholesterolMg: 0,
    sodiumMg: 0,
    calciumMg: 0,
    ironMg: 0,
    potassiumMg: 0,
    vitaminAIu: 0,
    vitaminCMg: 0,
    vitaminDMcg: 0,
  };
  const seen = new Set<keyof NutritionFactsDaySummary>();

  for (const t of entries) {
    if (t.sourceType !== "journal" || !t.transcriptText || t.journalCategory !== "nutrition") continue;
    let itemDayKey: string | null = null;
    if (
      typeof t.journalEntryYear === "number" &&
      typeof t.journalEntryMonth === "number" &&
      typeof t.journalEntryDay === "number"
    ) {
      itemDayKey = toDayKey(new Date(t.journalEntryYear, t.journalEntryMonth - 1, t.journalEntryDay));
    } else if (t.createdAt) {
      const d = new Date(t.createdAt);
      if (!Number.isNaN(d.getTime())) itemDayKey = toDayKey(d);
    }
    if (itemDayKey !== dayKey) continue;

    for (const { key, pattern } of NUTRITION_FACT_PATTERNS) {
      const value = extractEstimatedNumber(t.transcriptText, pattern);
      if (value == null) continue;
      totals[key] += value;
      seen.add(key);
    }
  }

  const result = getEmptyNutritionFactsSummary();
  for (const { key } of NUTRITION_FACT_PATTERNS) {
    result[key] = seen.has(key) ? Math.round(totals[key]) : null;
  }
  return result;
}

function getNutritionContributorLabel(entry: {
  videoTitle?: string;
  transcriptText?: string;
}): string {
  const title = entry.videoTitle?.trim();
  if (title) return title;
  const foodLine = entry.transcriptText?.match(/- Food:\s*(.+)/i)?.[1]?.trim();
  if (foodLine) return foodLine;
  return "Entry";
}

function summarizeNutritionFactContributorsForDay(
  entries: Array<{
    sourceType?: "youtube" | "journal";
    transcriptText?: string;
    journalCategory?: "nutrition" | "exercise";
    journalEntryYear?: number;
    journalEntryMonth?: number;
    journalEntryDay?: number;
    createdAt?: string;
    videoTitle?: string;
  }>,
  dayKey: string
): NutritionFactContributorsByKey {
  const perKeyTotalsByLabel: Record<keyof NutritionFactsDaySummary, Map<string, number>> = {
    calories: new Map(),
    totalCarbohydratesGrams: new Map(),
    dietaryFiberGrams: new Map(),
    sugarGrams: new Map(),
    addedSugarsGrams: new Map(),
    sugarAlcoholsGrams: new Map(),
    netCarbsGrams: new Map(),
    proteinGrams: new Map(),
    totalFatGrams: new Map(),
    saturatedFatGrams: new Map(),
    transFatGrams: new Map(),
    polyunsaturatedFatGrams: new Map(),
    monounsaturatedFatGrams: new Map(),
    cholesterolMg: new Map(),
    sodiumMg: new Map(),
    calciumMg: new Map(),
    ironMg: new Map(),
    potassiumMg: new Map(),
    vitaminAIu: new Map(),
    vitaminCMg: new Map(),
    vitaminDMcg: new Map(),
  };

  for (const t of entries) {
    if (t.sourceType !== "journal" || !t.transcriptText || t.journalCategory !== "nutrition") continue;
    let itemDayKey: string | null = null;
    if (
      typeof t.journalEntryYear === "number" &&
      typeof t.journalEntryMonth === "number" &&
      typeof t.journalEntryDay === "number"
    ) {
      itemDayKey = toDayKey(new Date(t.journalEntryYear, t.journalEntryMonth - 1, t.journalEntryDay));
    } else if (t.createdAt) {
      const d = new Date(t.createdAt);
      if (!Number.isNaN(d.getTime())) itemDayKey = toDayKey(d);
    }
    if (itemDayKey !== dayKey) continue;

    const label = getNutritionContributorLabel(t);
    for (const { key, pattern } of NUTRITION_FACT_PATTERNS) {
      const value = extractEstimatedNumber(t.transcriptText, pattern);
      if (value == null || value <= 0) continue;
      perKeyTotalsByLabel[key].set(label, (perKeyTotalsByLabel[key].get(label) ?? 0) + value);
    }
  }

  const result: NutritionFactContributorsByKey = {};
  for (const { key } of NUTRITION_FACT_PATTERNS) {
    const contributors = Array.from(perKeyTotalsByLabel[key].entries())
      .map(([label, value]) => ({ label, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 3);
    if (contributors.length > 0) result[key] = contributors;
  }
  return result;
}

function summarizeNutritionForDay(
  entries: Array<{
    sourceType?: "youtube" | "journal";
    transcriptText?: string;
    journalCategory?: "nutrition" | "exercise";
    journalEntryYear?: number;
    journalEntryMonth?: number;
    journalEntryDay?: number;
    createdAt?: string;
  }>,
  dayKey: string,
  caloriesTarget: number,
  habitCalories?: {
    habits: Array<{ _id: string; calorieImpact?: { type: "intake" | "burn"; calories: number; label: string } | null }>;
    completions: Record<string, string[]>;
  }
): {
  caloriesFood: number;
  caloriesExercise: number;
  caloriesRemaining: number;
  carbsGrams: number;
  proteinGrams: number;
  fatGrams: number;
} {
  let caloriesFood = 0;
  let caloriesExercise = 0;
  let carbsGrams = 0;
  let proteinGrams = 0;
  let fatGrams = 0;

  for (const t of entries) {
    if (t.sourceType !== "journal" || !t.transcriptText) continue;
    if (t.transcriptText.includes("Source: Habit completion")) continue;
    let itemDayKey: string | null = null;
    if (
      typeof t.journalEntryYear === "number" &&
      typeof t.journalEntryMonth === "number" &&
      typeof t.journalEntryDay === "number"
    ) {
      itemDayKey = toDayKey(new Date(t.journalEntryYear, t.journalEntryMonth - 1, t.journalEntryDay));
    } else if (t.createdAt) {
      const d = new Date(t.createdAt);
      if (!Number.isNaN(d.getTime())) itemDayKey = toDayKey(d);
    }
    if (itemDayKey !== dayKey) continue;

    if (t.journalCategory === "nutrition") {
      const calories = extractEstimatedNumber(t.transcriptText, /- Calories:\s*([\d.]+)\s*kcal/i);
      const carbs = extractEstimatedNumber(t.transcriptText, /- Carbs:\s*([\d.]+)\s*g/i);
      const protein = extractEstimatedNumber(t.transcriptText, /- Protein:\s*([\d.]+)\s*g/i);
      const fat = extractEstimatedNumber(t.transcriptText, /- Fat:\s*([\d.]+)\s*g/i);
      if (calories !== null) caloriesFood += calories;
      if (carbs !== null) carbsGrams += carbs;
      if (protein !== null) proteinGrams += protein;
      if (fat !== null) fatGrams += fat;
    }

    if (t.journalCategory === "exercise") {
      const burned = extractEstimatedNumber(t.transcriptText, /- Calories burned:\s*([\d.]+)\s*kcal/i);
      const carbsUsed = extractEstimatedNumber(t.transcriptText, /- Carbs used:\s*([-\d.]+)\s*g/i);
      const fatUsed = extractEstimatedNumber(t.transcriptText, /- Fat used:\s*([-\d.]+)\s*g/i);
      const proteinDelta = extractEstimatedNumber(t.transcriptText, /- Protein delta:\s*([-\d.]+)\s*g/i);
      if (burned !== null) caloriesExercise += burned;
      if (carbsUsed !== null) carbsGrams -= carbsUsed;
      if (fatUsed !== null) fatGrams -= fatUsed;
      if (proteinDelta !== null) proteinGrams += proteinDelta;
    }
  }

  if (habitCalories) {
    for (const h of habitCalories.habits) {
      if (!h.calorieImpact || h.calorieImpact.calories <= 0) continue;
      const completedDays = habitCalories.completions[h._id];
      if (!completedDays || !completedDays.includes(dayKey)) continue;
      if (h.calorieImpact.type === "intake") {
        caloriesFood += h.calorieImpact.calories;
      } else {
        caloriesExercise += h.calorieImpact.calories;
      }
    }
  }

  return {
    caloriesFood: Math.round(caloriesFood),
    caloriesExercise: Math.round(caloriesExercise),
    caloriesRemaining: Math.round(caloriesTarget - caloriesFood + caloriesExercise),
    carbsGrams: Math.max(0, Math.round(carbsGrams)),
    proteinGrams: Math.max(0, Math.round(proteinGrams)),
    fatGrams: Math.round(fatGrams),
  };
}

function hasMeaningfulNutritionData(snapshot: {
  caloriesFood: number;
  caloriesExercise: number;
  carbsGrams: number;
  proteinGrams: number;
  fatGrams: number;
}): boolean {
  return (
    snapshot.caloriesFood > 0 ||
    snapshot.caloriesExercise > 0 ||
    snapshot.carbsGrams > 0 ||
    snapshot.proteinGrams > 0 ||
    snapshot.fatGrams > 0
  );
}

function extractCalorieJournalDisplaySections(text: string): {
  enrichedEntry: string | null;
  assumptions: string[];
} {
  const normalized = text.replace(/\r/g, "");
  const enrichedMatch = /Enriched entry:\s*([\s\S]*?)(?:\n\n|$)/i.exec(normalized);
  const enrichedEntry = enrichedMatch?.[1]?.trim() ? enrichedMatch[1].trim() : null;

  const assumptionsHeaderIdx = normalized.search(/Assumptions:\s*/i);
  if (assumptionsHeaderIdx < 0) {
    return { enrichedEntry, assumptions: [] };
  }
  const assumptionsBlock = normalized.slice(assumptionsHeaderIdx).replace(/^Assumptions:\s*/i, "").trim();
  if (!assumptionsBlock) return { enrichedEntry, assumptions: [] };

  const assumptions = assumptionsBlock
    .split(/\n+/)
    .flatMap((line) => line.split(/\s+-\s+/))
    .map((part) => part.replace(/^\s*-\s*/, "").trim())
    .filter(Boolean);

  return { enrichedEntry, assumptions };
}

function clampToRange(value: number, min: number, max: number): number {
  return Math.round(Math.max(min, Math.min(max, value)));
}

function toNumericInputValue(value: unknown): number | null {
  if (typeof value === "number" && Number.isFinite(value)) return value;
  if (typeof value === "string" && value.trim()) {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) return parsed;
  }
  return null;
}

function parseNullableNumericInput(value: string): number | null {
  const trimmed = value.trim();
  if (!trimmed) return null;
  const parsed = Number(trimmed);
  return Number.isFinite(parsed) ? parsed : null;
}

function kgFromWeightInput(value: string, unit: WeightUnit): number | null {
  const numeric = toNumericInputValue(value);
  if (numeric === null || numeric <= 0) return null;
  if (unit === "lb") return numeric * 0.45359237;
  return numeric;
}

function cmFromHeightInput(profile: GoalsWizardProfile): number | null {
  if (profile.heightUnit === "cm") {
    const cm = toNumericInputValue(profile.heightCm);
    return cm !== null && cm > 0 ? cm : null;
  }
  const feet = toNumericInputValue(profile.heightFeet);
  const inches = toNumericInputValue(profile.heightInches);
  if (feet === null && inches === null) return null;
  const totalInches = (feet ?? 0) * 12 + (inches ?? 0);
  if (totalInches <= 0) return null;
  return totalInches * 2.54;
}

function deriveMacroPercentsFromGoals(goals: {
  caloriesTarget: number;
  carbsGrams: number;
  proteinGrams: number;
  fatGrams: number;
}): { carbs: number; protein: number; fat: number } {
  const totalMacroCalories = goals.carbsGrams * 4 + goals.proteinGrams * 4 + goals.fatGrams * 9;
  const denominator = goals.caloriesTarget > 0 ? goals.caloriesTarget : totalMacroCalories;
  if (!Number.isFinite(denominator) || denominator <= 0) {
    return { carbs: 40, protein: 30, fat: 30 };
  }
  const carbs = Math.max(
    GOAL_PERCENT_MIN,
    Math.min(GOAL_PERCENT_MAX, Math.round((goals.carbsGrams * 4 * 100) / denominator))
  );
  const protein = Math.max(
    GOAL_PERCENT_MIN,
    Math.min(GOAL_PERCENT_MAX, Math.round((goals.proteinGrams * 4 * 100) / denominator))
  );
  const fat = Math.max(GOAL_PERCENT_MIN, Math.min(GOAL_PERCENT_MAX, 100 - carbs - protein));
  return { carbs, protein, fat };
}

function createDefaultGoalsWizardProfile(): GoalsWizardProfile {
  return {
    age: "32",
    gender: "male",
    heightUnit: "ft",
    heightFeet: "5",
    heightInches: "7",
    heightCm: "170",
    weightValue: "73",
    weightUnit: "kg",
    goal: "lose_weight",
    targetWeightValue: "68",
    targetWeightUnit: "kg",
    pace: "extreme",
  };
}

function normalizeNutritionFatLossMethod(value: unknown): NutritionFatLossMethod {
  if (value === "intermittent_fasting" || value === "diet_based") return value;
  return "calorie_counting";
}

function nutritionMethodLabel(method: NutritionFatLossMethod): string {
  if (method === "intermittent_fasting") return "Intermittent fasting";
  if (method === "diet_based") return "Diet-based";
  return "Calorie counting";
}

function formatHourLabel(hour: number): string {
  const normalized = ((hour % 24) + 24) % 24;
  const whole = Math.floor(normalized);
  const minutes = Math.round((normalized - whole) * 60);
  const adjustedHour = minutes === 60 ? (whole + 1) % 24 : whole;
  const adjustedMinutes = minutes === 60 ? 0 : minutes;
  const displayHour = adjustedHour % 12 === 0 ? 12 : adjustedHour % 12;
  const suffix = adjustedHour >= 12 ? "PM" : "AM";
  return `${displayHour}:${String(adjustedMinutes).padStart(2, "0")} ${suffix}`;
}

function formatMinuteOfDay(minuteOfDay: number): string {
  const bounded = Math.max(0, Math.min(1439, Math.floor(minuteOfDay)));
  const hour = Math.floor(bounded / 60);
  const minute = bounded % 60;
  return formatHourLabel(hour + minute / 60);
}

function parseExerciseDurationMinutesFromText(text: string): number {
  const match = text.match(/- Duration:\s*([\d.]+)\s*(?:min|mins|minute|minutes)\b/i);
  const value = match?.[1] ? Number(match[1]) : NaN;
  if (!Number.isFinite(value)) return 45;
  return Math.max(5, Math.min(360, Math.round(value)));
}

const CAFFEINE_HALF_LIFE_MINUTES = 300;

function parseCaffeineMgFromJournalText(text: string): number | null {
  const match = /- Caffeine:\s*([\d.]+)\s*mg/i.exec(text);
  if (match) {
    const n = Number(match[1]);
    if (Number.isFinite(n) && n > 0) return n;
  }
  const lower = text.toLowerCase();
  if (/\bespresso\b/.test(lower)) return 63;
  if (/\bmatcha\b/.test(lower)) return 70;
  if (/\benergy\s*drink\b/.test(lower)) return 80;
  if (/\bcoffee\b/.test(lower)) return 95;
  if (/\bgreen\s*tea\b/.test(lower)) return 28;
  if (/\bblack\s*tea\b/.test(lower)) return 47;
  if (/\btea\b/.test(lower)) return 47;
  return null;
}

function computeCaffeineAtMinute(
  intakes: ReadonlyArray<{ minuteOfDay: number; mg: number }>,
  minute: number
): number {
  let total = 0;
  for (const intake of intakes) {
    const elapsed = minute - intake.minuteOfDay;
    if (elapsed < 0) continue;
    total += intake.mg * Math.pow(0.5, elapsed / CAFFEINE_HALF_LIFE_MINUTES);
  }
  return total;
}

function computePeakFocusWindow(
  intakes: ReadonlyArray<{ minuteOfDay: number; mg: number }>
): { startMinute: number; endMinute: number } | null {
  if (intakes.length === 0) return null;
  let bestStart = 0;
  let bestAvg = 0;
  const earliest = Math.min(...intakes.map((i) => i.minuteOfDay));
  const searchStart = earliest + 20;
  const searchEnd = Math.min(1380, earliest + 720);
  for (let start = searchStart; start <= searchEnd; start += 5) {
    let sum = 0;
    for (let m = start; m < start + 60; m += 5) {
      sum += computeCaffeineAtMinute(intakes, m);
    }
    const avg = sum / 12;
    if (avg > bestAvg) {
      bestAvg = avg;
      bestStart = start;
    }
  }
  if (bestAvg <= 0) return null;
  return { startMinute: bestStart, endMinute: Math.min(1440, bestStart + 60) };
}

function computeSuggestedFocusMinutes(
  sleepHours: number,
  hrvMs: number | null
): { minutes: number; reason: string } {
  if (sleepHours >= 7 && hrvMs != null && hrvMs >= 50)
    return { minutes: 90, reason: "Well recovered — deep work" };
  if (sleepHours >= 7)
    return { minutes: 60, reason: "Good sleep — steady focus" };
  if (sleepHours >= 5)
    return { minutes: 30, reason: "Light sleep — shorter sprints" };
  return { minutes: 15, reason: "Low recovery — micro sessions" };
}

function normalizeNutritionMethodConfigInput(
  value: unknown
): NutritionMethodConfig {
  const obj = value && typeof value === "object" ? (value as Record<string, unknown>) : {};
  const fastingRaw = toNumericInputValue(obj.intermittentFastingEatingWindowHours);
  const fastingHours =
    fastingRaw === null
      ? DEFAULT_FASTING_EATING_WINDOW_HOURS
      : clampToRange(fastingRaw, 4, 16);
  const template =
    obj.dietBasedTemplate === "low_carb" ||
    obj.dietBasedTemplate === "high_protein" ||
    obj.dietBasedTemplate === "low_fat" ||
    obj.dietBasedTemplate === "balanced"
      ? obj.dietBasedTemplate
      : DEFAULT_DIET_BASED_TEMPLATE;
  return {
    intermittentFastingEatingWindowHours: fastingHours,
    dietBasedTemplate: template,
  };
}

function normalizeGoalValue(
  value: unknown,
  fallback: number,
  min: number,
  max: number
): number {
  const parsed = typeof value === "number" ? value : Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return clampToRange(parsed, min, max);
}

function getGoalSpectrumTextClass(current: number, target: number): string {
  if (!Number.isFinite(current) || !Number.isFinite(target) || target <= 0) {
    return "text-foreground";
  }
  const ratio = current / target;
  if (ratio <= 0.25) return "text-red-600 dark:text-red-400";
  if (ratio <= 0.5) return "text-orange-600 dark:text-orange-400";
  if (ratio <= 0.9) return "text-yellow-600 dark:text-yellow-400";
  if (ratio <= 1.1) return "text-emerald-600 dark:text-emerald-400";
  if (ratio <= 1.35) return "text-yellow-600 dark:text-yellow-400";
  if (ratio <= 1.6) return "text-orange-600 dark:text-orange-400";
  return "text-red-600 dark:text-red-400";
}

function getMacroMeterFillClass(
  macroType: "carbs" | "protein" | "fat",
  current: number,
  target: number
): string {
  if (!Number.isFinite(current) || !Number.isFinite(target) || target <= 0) {
    return "bg-neutral-400 dark:bg-neutral-500";
  }
  const ratio = current / target;
  if (macroType === "protein") {
    // Protein uses the inverse goal-progress scale:
    // 0-25% red, 25-50% orange, 50-75% yellow, 75-100% green, >100% deep green.
    if (ratio <= 0.25) return "bg-red-500 dark:bg-red-400";
    if (ratio <= 0.5) return "bg-orange-500 dark:bg-orange-400";
    if (ratio <= 0.75) return "bg-yellow-500 dark:bg-yellow-400";
    if (ratio <= 1) return "bg-emerald-500 dark:bg-emerald-400";
    return "bg-emerald-800 dark:bg-emerald-700";
  }
  // Carbs and fat share this threshold scale:
  // 0-50% green, 50-75% yellow, 75-100% red, >100% deep red.
  if (ratio <= 0.5) return "bg-emerald-500 dark:bg-emerald-400";
  if (ratio <= 0.75) return "bg-yellow-500 dark:bg-yellow-400";
  if (ratio <= 1) return "bg-red-500 dark:bg-red-400";
  return "bg-red-800 dark:bg-red-700";
}

function getMacroMeterWidth(current: number, target: number): string {
  if (!Number.isFinite(current) || !Number.isFinite(target) || target <= 0) {
    return "0%";
  }
  return `${Math.max(0, Math.min(100, (current / target) * 100))}%`;
}

function getCaloriesRemainingMeterFillClass(remaining: number, target: number): string {
  if (!Number.isFinite(remaining) || !Number.isFinite(target) || target <= 0) {
    return "bg-neutral-400 dark:bg-neutral-500";
  }
  const ratio = remaining / target;
  if (ratio < 0) return "bg-red-800 dark:bg-red-700";
  if (ratio < 0.15) return "bg-red-500 dark:bg-red-400";
  if (ratio < 0.35) return "bg-orange-500 dark:bg-orange-400";
  if (ratio < 0.6) return "bg-yellow-500 dark:bg-yellow-400";
  return "bg-emerald-500 dark:bg-emerald-400";
}

