    if (params.get("journalSaved") !== "1") return;
    setJournalEntryJustSaved(true);
    refetchTranscripts();
    router.replace("/chat/new", { scroll: false });
    const tid = window.setTimeout(() => setJournalEntryJustSaved(false), 4000);
    return () => clearTimeout(tid);
