  useEffect(() => {
    if (language === "en" || isAnonymous) {
      setTranslatedTitles({});
      return;
    }
    const items: { id: string; title: string }[] = [
      ...longTermMemories.map((l) => ({ id: l._id, title: l.title || "" })),
      ...customConcepts.map((c) => ({ id: c._id, title: c.title || "" })),
      ...conceptGroups.map((g) => ({ id: g._id, title: g.title || "" })),
    ].filter((i) => i.title.trim());
    if (items.length === 0) {
      setTranslatedTitles({});
      return;
    }
    fetch("/api/me/translate-titles", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ items, language }),
    })
      .then((r) => (r.ok ? r.json() : Promise.reject()))
      .then((data: { translations?: Record<string, string> }) => {
        setTranslatedTitles(data.translations ?? {});
      })
      .catch(() => setTranslatedTitles({}));
  }, [language, isAnonymous, longTermMemories, customConcepts, conceptGroups]);

  useEffect(() => {
    if (isAnonymous && !isNew) {
      setSessionLoading(false);
      return;
    }
    if (incognitoMode) {
      setSessionLoading(false);
      return;
    }
    if (!isNew && sessionId && sessionId !== "new" && sessionId !== "incognito") {
      // Skip fetch when we just created this session and streamed the response.
      // Fetching would overwrite our streamed messages and cause a visible refresh.
      if (justCreatedSessionRef.current === sessionId) {
        return;
      }
      justCreatedSessionRef.current = null; // clear before fetching a different session
      setSessionLoading(true);
      fetch(`/api/sessions/${sessionId}`)
        .then((r) => {
          if (!r.ok) throw new Error("Not found");
          return r.json();
        })
        .then(({ session, messages: msgs, longTermMemory }) => {
          setCurrentSessionId(session._id);
          setCurrentSession(session);
          activeResponseVerbosityRef.current = parseResponseVerbosity(session.responseVerbosity) ?? "compact";
          if (session.oneOnOneMentorFigureId && session.oneOnOneMentorFigureName) {
            activeOneOnOneMentorRef.current = {
              id: session.oneOnOneMentorFigureId,
              name: session.oneOnOneMentorFigureName,
            };
            activeSecondOrderRef.current = false;
            activeSecondOrderPlainRef.current = false;
            setPendingSecondOrder(false);
          } else {
            activeOneOnOneMentorRef.current = null;
            if (session.secondOrderThinking) {
              activeSecondOrderRef.current = true;
              activeSecondOrderPlainRef.current = session.secondOrderPlain !== false;
              setPendingOneOnOneMentor(null);
            } else {
              activeSecondOrderRef.current = false;
              activeSecondOrderPlainRef.current = false;
              setPendingSecondOrder(false);
            }
          }
          setMessages(processMessagesWithContext(msgs || []));
          setCollapsedSummary(session.isCollapsed && longTermMemory ? longTermMemory : null);
        })
        .catch(() => {
          router.push("/chat/new");
        })
        .finally(() => setSessionLoading(false));
    } else if (isNew || isAnonymous || incognitoMode) {
      setSessionLoading(false);
      // Check for perspective card "Start conversation" — opens in new conversation
      if (typeof window !== "undefined" && isNew && !incognitoMode) {
        try {
          activeResponseVerbosityRef.current = "compact";
          const storedVerbosityRaw = sessionStorage.getItem(RESPONSE_VERBOSITY_START_KEY);
          if (storedVerbosityRaw) {
            sessionStorage.removeItem(RESPONSE_VERBOSITY_START_KEY);
            const storedVerbosity = parseResponseVerbosity(storedVerbosityRaw);
            if (storedVerbosity) {
              activeResponseVerbosityRef.current = storedVerbosity;
            }
          }
          const stored = sessionStorage.getItem(PERSPECTIVE_CARD_START_KEY);
          if (stored) {
            activeOneOnOneMentorRef.current = null;
            sessionStorage.removeItem(PERSPECTIVE_CARD_START_KEY);
            const parsed = JSON.parse(stored) as {
              assistantContent?: string;
              prompt: string;
              name: string;
              figure?: { id: string; name: string };
              fetchFigureOnLoad?: boolean;
            };
            const { prompt, name } = parsed;
            if (parsed.fetchFigureOnLoad) {
            setMessages([{
              role: "assistant",
                content: "Finding your guide…",
              perspectiveCard: { name, prompt },
            }]);
              setPendingCardFetch({ prompt, name });
            } else {
              if (parsed.figure) setActiveConversationFigure(parsed.figure);
              setMessages([{
                role: "assistant",
                content: parsed.assistantContent ?? buildPerspectiveCardMessage(language, prompt, parsed.figure),
                perspectiveCard: { name, prompt },
              }]);
              setPendingCardContext({ prompt, name, figure: parsed.figure });
            }
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            return;
          }
          const mentorStored = sessionStorage.getItem(MENTOR_ONE_ON_ONE_START_KEY);
          if (mentorStored) {
            sessionStorage.removeItem(MENTOR_ONE_ON_ONE_START_KEY);
            const parsed = JSON.parse(mentorStored) as {
              figureId: string;
              figureName: string;
              figureDescription?: string;
              journalText?: string;
              reflectionText?: string;
            };
            const figure = {
              id: parsed.figureId,
              name: parsed.figureName,
              description: parsed.figureDescription,
            };
            if (typeof parsed.journalText === "string" || typeof parsed.reflectionText === "string") {
              mentorJournalBridgeRef.current = {
                journalText: typeof parsed.journalText === "string" ? parsed.journalText : "",
                reflectionText: typeof parsed.reflectionText === "string" ? parsed.reflectionText : "",
              };
            } else {
              mentorJournalBridgeRef.current = null;
            }
            const journalForAutoSend =
              typeof parsed.journalText === "string" ? parsed.journalText.trim() : "";
            const useJournalBridgeAutoReply = journalForAutoSend.length > 0;
            activeOneOnOneMentorRef.current = {
              id: figure.id,
              name: figure.name,
              description: figure.description,
            };
            setPendingOneOnOneMentor({
              id: figure.id,
              name: figure.name,
              description: figure.description,
            });
            setSelectedMentorFigureIds([]);
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            if (useJournalBridgeAutoReply) {
              setMessages([]);
              queueJournalBridgeAutoSend(journalForAutoSend);
            } else {
              setMessages([
                {
                  role: "assistant",
                  content: buildMentorOneOnOneMessage(language, figure),
                  mentorOneOnOne: { id: figure.id, name: figure.name },
                },
              ]);
            }
            return;
          }
          const secondOrderStored = sessionStorage.getItem(SECOND_ORDER_START_KEY);
          if (secondOrderStored) {
            sessionStorage.removeItem(SECOND_ORDER_START_KEY);
            activeOneOnOneMentorRef.current = null;
            setPendingOneOnOneMentor(null);
            activeSecondOrderRef.current = true;
            let plainHandoff = true;
            try {
              const parsed = JSON.parse(secondOrderStored) as { plain?: boolean };
              if (parsed && typeof parsed === "object" && typeof parsed.plain === "boolean") {
                plainHandoff = parsed.plain;
              }
            } catch {
              plainHandoff = secondOrderStored === "1" || secondOrderStored === "true";
            }
            activeSecondOrderPlainRef.current = plainHandoff;
            setPendingSecondOrder(true);
            setMessages([
              {
                role: "assistant",
                content: buildSecondOrderMessage(language),
                secondOrderThinking: true,
                secondOrderPlain: plainHandoff,
              },
            ]);
            setSelectedMentorFigureIds([]);
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            return;
          }
          const waysFromChooser = sessionStorage.getItem(OPEN_WAYS_FROM_CHOOSER_KEY);
          if (waysFromChooser) {
            sessionStorage.removeItem(OPEN_WAYS_FROM_CHOOSER_KEY);
            activeOneOnOneMentorRef.current = null;
            setPendingOneOnOneMentor(null);
            activeSecondOrderRef.current = false;
            activeSecondOrderPlainRef.current = false;
            setPendingSecondOrder(false);
            setMessages([]);
            setLibraryPanelOpen(null);
            setWaysOfLookingAtModalOpen(true);
            setWaysOfLookingAtDrawMode(true);
            setWaysOfLookingAtCategory(null);
            setWaysOfLookingAtCity(null);
            setWaysOfLookingAtCuisine(null);
            setWaysOfLookingAtMicrocosm(null);
            setWaysOfLookingAtHuman(null);
            setWaysOfLookingAtDigital(null);
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            return;
          }
          const mentorPickerFromChooser = sessionStorage.getItem(MENTOR_PICKER_FROM_CHOOSER_KEY);
          if (mentorPickerFromChooser) {
            sessionStorage.removeItem(MENTOR_PICKER_FROM_CHOOSER_KEY);
            activeOneOnOneMentorRef.current = null;
            setPendingOneOnOneMentor(null);
            activeSecondOrderRef.current = false;
            activeSecondOrderPlainRef.current = false;
            setPendingSecondOrder(false);
            setMessages([]);
            setMentorCatalogSearch("");
            setMentorCatalogCategoryId(null);
            setMentorOneOnOneModalOpen(true);
            setSelectedMentorFigureIds([]);
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            return;
          }
          // Fallback when sessionStorage handoff is unavailable:
          // read card data from URL params and hydrate the new conversation.
          const params = new URLSearchParams(window.location.search);
          const verbosityQ = parseResponseVerbosity(params.get("rv"));
          if (verbosityQ) {
            activeResponseVerbosityRef.current = verbosityQ;
          }
          const prompt = params.get("pcPrompt");
          const name = params.get("pcName");
          const figureId = params.get("pcFigureId");
          const figureName = params.get("pcFigureName");
          if (prompt && name) {
            activeOneOnOneMentorRef.current = null;
            if (figureId && figureName) {
              const figure = { id: figureId, name: figureName };
              setActiveConversationFigure(figure);
              const assistantContent = buildPerspectiveCardMessage(language, prompt, figure);
            setMessages([{
              role: "assistant",
              content: assistantContent,
              perspectiveCard: { name, prompt },
            }]);
              setPendingCardContext({ prompt, name, figure });
            } else {
              setMessages([{
                role: "assistant",
                content: "Finding your guide…",
                perspectiveCard: { name, prompt },
              }]);
              setPendingCardFetch({ prompt, name });
            }
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            return;
          }
          const mentorId = params.get("mentorId");
          const mentorName = params.get("mentorName");
          const mentorDescription = params.get("mentorDescription");
          if (mentorId && mentorName) {
            mentorJournalBridgeRef.current = null;
            const figure = {
              id: mentorId,
              name: mentorName,
              description: mentorDescription || undefined,
            };
            activeOneOnOneMentorRef.current = {
              id: figure.id,
              name: figure.name,
              description: figure.description,
            };
            setMessages([
              {
                role: "assistant",
                content: buildMentorOneOnOneMessage(language, figure),
                mentorOneOnOne: { id: figure.id, name: figure.name },
              },
            ]);
            setPendingOneOnOneMentor({
              id: figure.id,
              name: figure.name,
              description: figure.description,
            });
            setSelectedMentorFigureIds([]);
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            return;
          }
          const secondOrderQ = params.get("secondOrder");
          if (secondOrderQ === "plain" || secondOrderQ === "1") {
            activeOneOnOneMentorRef.current = null;
            setPendingOneOnOneMentor(null);
            activeSecondOrderRef.current = true;
            activeSecondOrderPlainRef.current = true;
            setPendingSecondOrder(true);
            setMessages([
              {
                role: "assistant",
                content: buildSecondOrderMessage(language),
                secondOrderThinking: true,
                secondOrderPlain: true,
              },
            ]);
            setSelectedMentorFigureIds([]);
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            router.replace("/chat/new");
            return;
          }
          if (secondOrderQ === "citations") {
            activeOneOnOneMentorRef.current = null;
            setPendingOneOnOneMentor(null);
            activeSecondOrderRef.current = true;
            activeSecondOrderPlainRef.current = false;
            setPendingSecondOrder(true);
            setMessages([
              {
                role: "assistant",
                content: buildSecondOrderMessage(language),
                secondOrderThinking: true,
                secondOrderPlain: false,
              },
            ]);
            setSelectedMentorFigureIds([]);
            setCurrentSessionId(null);
            setCurrentSession(null);
            setCollapsedSummary(null);
            router.replace("/chat/new");
            return;
          }
        } catch {
          /* ignore */
        }
      }
      // Don't clear when we're streaming a response from a just-created session
      // (e.g. user selected a phrase from the carousel). Clearing would wipe the UI.
      // For anonymous users, we never set justCreatedSessionRef, so use anonymousActiveRef.
      // Also keep 1:1 mentor / second-order / perspective-card flows started from Ideas or URL:
      // those set active* refs before the first message; anonymousActiveRef only flips on send.
      const hasActiveConversation =
        justCreatedSessionRef.current ||
        (isAnonymous && anonymousActiveRef.current) ||
        activeOneOnOneMentorRef.current != null ||
        activeSecondOrderRef.current ||
        pendingCardFetchRef.current != null ||
        pendingCardContextRef.current != null;
      if (!(isNew && hasActiveConversation)) {
        setMessages([]);
        setCurrentSessionId(null);
        setCurrentSession(null);
        setCollapsedSummary(null);
        anonymousActiveRef.current = false;
        activeOneOnOneMentorRef.current = null;
        setPendingOneOnOneMentor(null);
        activeSecondOrderRef.current = false;
        activeSecondOrderPlainRef.current = false;
        setPendingSecondOrder(false);
      }
    }
  }, [sessionId, isNew, isAnonymous, incognitoMode, router, language, queueJournalBridgeAutoSend]);

  const [lastFailedUserMessage, setLastFailedUserMessage] = useState<string | null>(null);
  const [onboardingDismissed, setOnboardingDismissed] = useState(true);
  const [pendingCardContext, setPendingCardContext] = useState<{
    prompt: string;
    name: string;
    figure?: { id: string; name: string; description?: string };
  } | null>(null);
  const [activeConversationFigure, setActiveConversationFigure] = useState<{
    id: string;
    name: string;
    description?: string;
  } | null>(null);
  const [pendingCardFetch, setPendingCardFetch] = useState<{ prompt: string; name: string } | null>(null);
  pendingCardContextRef.current = pendingCardContext;
  pendingCardFetchRef.current = pendingCardFetch;

  const startConversationFromPerspectiveCard = useCallback(
    (
      { name, prompt }: { name: string; prompt: string },
      responseVerbosity: ResponseVerbosity = activeResponseVerbosityRef.current
    ) => {
      activeResponseVerbosityRef.current = responseVerbosity;
      activeSecondOrderRef.current = false;
      activeSecondOrderPlainRef.current = false;
      setPendingSecondOrder(false);
      setDrawnPerspectiveCard(null);
      setWaysOfLookingAtModalOpen(false);
      setWaysOfLookingAtDrawMode(false);
      setWaysOfLookingAtCategory(null);
      setWaysOfLookingAtCity(null);
      setWaysOfLookingAtCuisine(null);
      setWaysOfLookingAtMicrocosm(null);
      setWaysOfLookingAtHuman(null);
      setWaysOfLookingAtDigital(null);
      if (typeof window !== "undefined" && window.innerWidth < 1024) {
        setLibraryPanelOpen(null);
        setSidebarOpen(false);
      }
      if (sessionId !== "new" && sessionId !== "incognito") {
        try {
          sessionStorage.setItem(RESPONSE_VERBOSITY_START_KEY, responseVerbosity);
          sessionStorage.setItem(
            PERSPECTIVE_CARD_START_KEY,
            JSON.stringify({ prompt, name, fetchFigureOnLoad: true })
          );
        } catch {
          /* ignore */
        }
        router.push(
          `/chat/new?pcName=${encodeURIComponent(name)}&pcPrompt=${encodeURIComponent(prompt)}&rv=${encodeURIComponent(responseVerbosity)}`
        );
      } else {
        setMessages([{
          role: "assistant",
          content: "Finding your guide…",
          perspectiveCard: { name, prompt },
        }]);
        setPendingCardFetch({ prompt, name });
        setCurrentSessionId(null);
        setCurrentSession(null);
        setCollapsedSummary(null);
        inputRef.current?.focus();
      }
    },
    [router, sessionId]
  );

  const startConversationFromMentorOneOnOne = useCallback(
    (
      figure: { id: string; name: string; description: string },
      journalBridge?: { journalText: string; reflectionText: string },
      responseVerbosity: ResponseVerbosity = activeResponseVerbosityRef.current
    ) => {
      activeResponseVerbosityRef.current = responseVerbosity;
      activeSecondOrderRef.current = false;
      activeSecondOrderPlainRef.current = false;
      setPendingSecondOrder(false);
      setMentorOneOnOneModalOpen(false);
      setIdeasModalOpen(false);
      setMentorCatalogSearch("");
      setMentorCatalogCategoryId(null);
      setSelectedMentorFigureIds([]);
      const bridgePayload = journalBridge
        ? {
            journalText: truncateMentorJournalBridgeText(
              journalBridge.journalText,
              MENTOR_JOURNAL_BRIDGE_MAX_JOURNAL
            ),
            reflectionText: truncateMentorJournalBridgeText(
              journalBridge.reflectionText,
              MENTOR_JOURNAL_BRIDGE_MAX_REFLECTION
            ),
          }
        : null;
      mentorJournalBridgeRef.current = bridgePayload;
      setLibraryPanelOpen(null);
      if (typeof window !== "undefined" && window.innerWidth < 1024) {
        setSidebarOpen(false);
      }
      if (sessionId !== "new" && sessionId !== "incognito") {
        try {
          sessionStorage.setItem(RESPONSE_VERBOSITY_START_KEY, responseVerbosity);
          sessionStorage.setItem(
            MENTOR_ONE_ON_ONE_START_KEY,
            JSON.stringify({
              figureId: figure.id,
              figureName: figure.name,
              figureDescription: figure.description,
              ...(bridgePayload
                ? { journalText: bridgePayload.journalText, reflectionText: bridgePayload.reflectionText }
                : {}),
            })
          );
        } catch {
          /* ignore */
        }
        router.push(
          `/chat/new?mentorId=${encodeURIComponent(figure.id)}&mentorName=${encodeURIComponent(figure.name)}&mentorDescription=${encodeURIComponent(figure.description)}&rv=${encodeURIComponent(responseVerbosity)}`
        );
      } else {
        activeOneOnOneMentorRef.current = {
          id: figure.id,
          name: figure.name,
          description: figure.description,
        };
        setPendingOneOnOneMentor({
          id: figure.id,
          name: figure.name,
          description: figure.description,
        });
        setCurrentSessionId(null);
        setCurrentSession(null);
        setCollapsedSummary(null);
        const journalTrimmed = bridgePayload?.journalText?.trim() ?? "";
        if (bridgePayload && journalTrimmed.length > 0) {
          setMessages([]);
          queueJournalBridgeAutoSend(journalTrimmed);
        } else {
          setMessages([
            {
              role: "assistant",
              content: buildMentorOneOnOneMessage(language, figure),
              mentorOneOnOne: { id: figure.id, name: figure.name },
            },
          ]);
          inputRef.current?.focus();
        }
      }
    },
    [router, sessionId, language, queueJournalBridgeAutoSend]
  );

  const startSecondOrderConversation = useCallback(
    (
      plain: boolean,
      responseVerbosity: ResponseVerbosity = activeResponseVerbosityRef.current
    ) => {
    activeResponseVerbosityRef.current = responseVerbosity;
    setNewConversationChooserModalOpen(false);
    setIdeasModalOpen(false);
    activeOneOnOneMentorRef.current = null;
    setPendingOneOnOneMentor(null);
    if (typeof window !== "undefined" && window.innerWidth < 1024) {
      setLibraryPanelOpen(null);
      setSidebarOpen(false);
    }
    if (sessionId !== "new" && sessionId !== "incognito") {
      try {
        sessionStorage.setItem(RESPONSE_VERBOSITY_START_KEY, responseVerbosity);
        sessionStorage.setItem(SECOND_ORDER_START_KEY, JSON.stringify({ plain }));
      } catch {
        /* ignore */
      }
      router.push(
        plain
          ? `/chat/new?secondOrder=plain&rv=${encodeURIComponent(responseVerbosity)}`
          : `/chat/new?secondOrder=citations&rv=${encodeURIComponent(responseVerbosity)}`
      );
    } else {
      activeSecondOrderRef.current = true;
      activeSecondOrderPlainRef.current = plain;
      setPendingSecondOrder(true);
      setMessages([
        {
          role: "assistant",
          content: buildSecondOrderMessage(language),
          secondOrderThinking: true,
          secondOrderPlain: plain,
        },
      ]);
      setSelectedMentorFigureIds([]);
      setCurrentSessionId(null);
      setCurrentSession(null);
      setCollapsedSummary(null);
      inputRef.current?.focus();
    }
  }, [router, sessionId, language]);

  useEffect(() => {
    if (!pendingCardFetch) return;
    let cancelled = false;
    (async () => {
      let figure: { id: string; name: string; description?: string } | undefined;
      try {
        const res = await fetch("/api/perspective-card/select-figure", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ prompt: pendingCardFetch.prompt, cardName: pendingCardFetch.name }),
        });
        if (cancelled) return;
        if (res.ok) {
          const data = await res.json();
          if (data?.id && data?.name) {
            figure = { id: data.id, name: data.name, description: data.description };
          }
        }
      } catch {
        /* ignore */
      }
      if (cancelled) return;
      const assistantContent = buildPerspectiveCardMessage(language, pendingCardFetch.prompt, figure);
      setMessages([{
        role: "assistant",
        content: assistantContent,
        perspectiveCard: { name: pendingCardFetch.name, prompt: pendingCardFetch.prompt },
      }]);
      setPendingCardContext({ prompt: pendingCardFetch.prompt, name: pendingCardFetch.name, figure });
      if (figure) setActiveConversationFigure(figure);
      setPendingCardFetch(null);
      inputRef.current?.focus();
    })();
    return () => {
      cancelled = true;
    };
  }, [pendingCardFetch, language]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    setOnboardingDismissed(!!localStorage.getItem("and-then-what-onboarding-seen"));
  }, []);

  const dismissOnboarding = useCallback(() => {
    try {
      localStorage.setItem("and-then-what-onboarding-seen", "true");
    } catch {
      /* ignore */
    }
    setOnboardingDismissed(true);
  }, []);

  const flushComposerInputSync = useCallback((nextValue: string) => {
    if (composerInputSyncTimeoutRef.current) {
      clearTimeout(composerInputSyncTimeoutRef.current);
      composerInputSyncTimeoutRef.current = null;
    }
    setInput(nextValue);
  }, []);

  const replaceComposerInput = useCallback((nextValue: string) => {
    composerDraftRef.current = nextValue;
    flushComposerInputSync(nextValue);
    setComposerInputSyncRevision((prev) => prev + 1);
  }, [flushComposerInputSync]);

  const handleMainInputChange = useCallback((nextValue: string) => {
    composerDraftRef.current = nextValue;
    if (chatInputLensRefinedText) setChatInputLensRefinedText("");
    if (chatInputLensError) setChatInputLensError(null);
    if (composerInputSyncTimeoutRef.current) {
      clearTimeout(composerInputSyncTimeoutRef.current);
    }
    composerInputSyncTimeoutRef.current = setTimeout(() => {
      composerInputSyncTimeoutRef.current = null;
      setInput(nextValue);
    }, 120);
  }, [chatInputLensError, chatInputLensRefinedText]);

  useEffect(() => {
    return () => {
      if (composerInputSyncTimeoutRef.current) {
        clearTimeout(composerInputSyncTimeoutRef.current);
      }
    };
  }, []);

  const refineMainInputWithLens = useCallback(async () => {
    const trimmed = composerDraftRef.current.trim();
    if (!trimmed || chatInputLens === "none" || chatInputLensLoading) return;
    setChatInputLensLoading(true);
    setChatInputLensError(null);
    try {
      const res = await fetch("/api/chat/refine", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          text: trimmed,
          lens: chatInputLens,
        }),
      });
      const data = (await res.json().catch(() => ({}))) as { refinedText?: string; error?: string };
      if (!res.ok) {
        throw new Error(data.error || "Could not refine message.");
      }
      const refinedText = typeof data.refinedText === "string" ? data.refinedText.trim() : "";
      if (!refinedText) {
        throw new Error("Could not refine message.");
      }
      setChatInputLensRefinedText(refinedText);
    } catch (error) {
      setChatInputLensError(error instanceof Error ? error.message : "Could not refine message.");
    } finally {
      setChatInputLensLoading(false);
    }
  }, [chatInputLens, chatInputLensLoading]);

  const chatLensSignalText = useMemo(() => {
    const trimmed = input.trim();
    if (trimmed) return trimmed;
    const recentConversation = messages
      .slice(-4)
      .map((m) => m.content)
      .join(" ");
    return recentConversation.trim();
  }, [input, messages]);
  const autoSuggestedChatLensMeta = useMemo(
    () => detectAutoSuggestedChatLens(chatLensSignalText),
    [chatLensSignalText]
  );

  useEffect(() => {
    if (chatInputLensLoading || chatInputLensRefinedText || chatInputLensError) {
      setChatInputLensMobileExpanded(true);
    }
  }, [chatInputLensError, chatInputLensLoading, chatInputLensRefinedText]);

  useEffect(() => {
    if (!chatInputLensMenuOpen) return;
    const onPointerDown = (event: MouseEvent) => {
      const target = event.target as Node | null;
      if (!target) return;
      if (chatInputLensMenuRef.current?.contains(target)) return;
      if (chatInputLensMenuButtonRef.current?.contains(target)) return;
      setChatInputLensMenuOpen(false);
    };
    const onEscape = (event: KeyboardEvent) => {
      if (event.key !== "Escape") return;
      setChatInputLensMenuOpen(false);
      chatInputLensMenuButtonRef.current?.focus();
    };
    document.addEventListener("mousedown", onPointerDown);
    document.addEventListener("keydown", onEscape);
    return () => {
      document.removeEventListener("mousedown", onPointerDown);
      document.removeEventListener("keydown", onEscape);
    };
  }, [chatInputLensMenuOpen]);

  const sendMessage = useCallback(async (overrideText?: string, options?: { retry?: boolean; messagesOverride?: Message[]; activeCardPrompt?: string; activeCardName?: string }) => {
    const rawText = (overrideText ?? composerDraftRef.current).trim();
    if (!rawText || isLoading) return;
    setMentorJournalBridgePending(false);
    playSelectionChime();

    if (isAnonymous) anonymousActiveRef.current = true;

    const cardCtx = pendingCardContext ?? (options?.activeCardPrompt && options?.activeCardName ? { prompt: options.activeCardPrompt, name: options.activeCardName } : null);
    if (cardCtx) setPendingCardContext(null);

    const hadPendingMentor = pendingOneOnOneMentor !== null;
    const journalBridgeSnapshot =
      hadPendingMentor && mentorJournalBridgeRef.current
        ? { ...mentorJournalBridgeRef.current }
        : null;
    const hadPendingSecondOrder = pendingSecondOrder;
    if (pendingOneOnOneMentor) {
      activeOneOnOneMentorRef.current = pendingOneOnOneMentor;
      setPendingOneOnOneMentor(null);
      activeSecondOrderRef.current = false;
      activeSecondOrderPlainRef.current = false;
      setPendingSecondOrder(false);
    }
    if (journalBridgeSnapshot) {
      mentorJournalBridgeRef.current = null;
    }
    if (pendingSecondOrder) {
      activeSecondOrderRef.current = true;
      setPendingSecondOrder(false);
      activeOneOnOneMentorRef.current = null;
    }
    const mentorForApi = activeOneOnOneMentorRef.current;

    const {
      cleanedMessage,
      mentionedMentalModelIds,
      mentionedLongTermMemoryIds,
      mentionedCustomConceptIds,
      mentionedConceptGroupIds,
    } = parseMentionsFromMessage(rawText, {
      idToName: mentalModelsIndex,
      ltmIdToTitle: new Map(longTermMemories.map((ltm) => [ltm._id, translatedTitles[ltm._id] ?? ltm.title])),
      ccIdToTitle: new Map(customConcepts.map((cc) => [cc._id, translatedTitles[cc._id] ?? cc.title])),
      cgIdToTitle: new Map(conceptGroups.map((cg) => [cg._id, translatedTitles[cg._id] ?? cg.title])),
    });
    const messageToSend =
      cleanedMessage ||
      (mentionedMentalModelIds.length > 0 || mentionedLongTermMemoryIds.length > 0 || mentionedCustomConceptIds.length > 0 || mentionedConceptGroupIds.length > 0
        ? "Please help me think through this."
        : rawText);
    const displayContent = cleanedMessage || messageToSend;

    if (messages.length === 0 && sessions.length === 0) {
      dismissOnboarding();
    }
    replaceComposerInput("");
    setChatInputLensRefinedText("");
    setChatInputLensError(null);
    setIsLoading(true);
    setLastFailedUserMessage(null);
    void playLlmResponseStartHaptic();

    const userMessage: Message = {
      role: "user",
      content: rawText,
      ...(!cardCtx && options?.activeCardPrompt &&
        options?.activeCardName && {
          perspectiveCard: {
            name: options.activeCardName,
            prompt: options.activeCardPrompt,
          },
        }),
    };
    const assistantPlaceholder =
      multiMentorMode && selectedMentorFigureIds.length >= 2
        ? `${selectedMentorFigureIds.length} mentors are responding…`
        : "";
    const assistantMessage: Message = { role: "assistant", content: assistantPlaceholder };
    const baseMessages = options?.messagesOverride ?? messages;
    setMessages((prev) =>
      options?.retry ? [...prev.slice(0, -2), userMessage, assistantMessage] : options?.messagesOverride ? [...options.messagesOverride, userMessage, assistantMessage] : [...prev, userMessage, assistantMessage]
    );

    let sid = currentSessionId;
    let didCreateSession = false;
    if (!sid && !isAnonymous && !incognitoMode) {
      const res = await fetch("/api/sessions", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title: messageToSend.slice(0, 50) }),
      });
      const newSession = await res.json();
      sid = newSession._id;
      justCreatedSessionRef.current = sid;
      didCreateSession = true;
      setCurrentSessionId(sid);
      setCurrentSession({ ...newSession, isCollapsed: false, updatedAt: new Date().toISOString() });
      setSessions((prev) => [{ ...newSession, updatedAt: new Date().toISOString() }, ...prev]);
      // Defer navigation until after chat completes - navigating mid-stream can unmount
      // the component and abort the fetch before the LLM responds.
    }

    const chatBody: Record<string, unknown> = {
      message: messageToSend,
      rawMessage: rawText,
      mentionedMentalModelIds,
      mentionedLongTermMemoryIds,
      mentionedCustomConceptIds,
      mentionedConceptGroupIds,
      language: languageRef.current,
      userType: userTypeRef.current,
      responseVerbosity: activeResponseVerbosityRef.current,
    };
    if (cardCtx) {
      chatBody.activeCardPrompt = cardCtx.prompt;
      chatBody.activeCardName = cardCtx.name;
      if (cardCtx.figure) {
        chatBody.activeCardFigureId = cardCtx.figure.id;
        chatBody.activeCardFigureName = cardCtx.figure.name;
      }
      if (!isAnonymous && !incognitoMode) {
        chatBody.prependMessages = [{ role: "assistant", content: buildPerspectiveCardMessage(languageRef.current, cardCtx.prompt, cardCtx.figure) }];
      }
    } else if (hadPendingMentor && mentorForApi && !cardCtx && !journalBridgeSnapshot) {
      if (!isAnonymous && !incognitoMode) {
        chatBody.prependMessages = [
          { role: "assistant", content: buildMentorOneOnOneMessage(languageRef.current, mentorForApi) },
        ];
      }
    } else if (
      hadPendingSecondOrder &&
      activeSecondOrderRef.current &&
      !mentorForApi &&
      !cardCtx
    ) {
      if (!isAnonymous && !incognitoMode) {
        chatBody.prependMessages = [
          { role: "assistant", content: buildSecondOrderMessage(languageRef.current) },
        ];
      }
    } else if (options?.activeCardPrompt) {
      chatBody.activeCardPrompt = options.activeCardPrompt;
      if (options?.activeCardName) chatBody.activeCardName = options.activeCardName;
    }
    if (
      multiMentorMode &&
      selectedMentorFigureIds.length >= 2 &&
      selectedMentorFigureIds.length <= 5 &&
      !mentorForApi
    ) {
      chatBody.multiMentorMode = true;
      chatBody.multiMentorFigureIds = selectedMentorFigureIds;
    }
    if (mentorForApi) {
      chatBody.oneOnOneMentorFigureId = mentorForApi.id;
    }
    if (journalBridgeSnapshot && mentorForApi) {
      chatBody.mentorJournalContext = journalBridgeSnapshot;
    }
    const useMultiMentorThisTurn =
      multiMentorMode &&
      selectedMentorFigureIds.length >= 2 &&
      selectedMentorFigureIds.length <= 5 &&
      !mentorForApi;
    if (activeSecondOrderRef.current && !mentorForApi && !cardCtx && !useMultiMentorThisTurn) {
      chatBody.secondOrderThinking = true;
      if (activeSecondOrderPlainRef.current) {
        chatBody.secondOrderPlain = true;
      }
    }
    if (isAnonymous || incognitoMode) {
      chatBody.messages = baseMessages.map((m) => ({ role: m.role, content: m.content }));
      if (incognitoMode) chatBody.incognito = true;
    } else {
      chatBody.sessionId = sid ?? undefined;
    }

    try {
      const res = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(chatBody),
      });

      if (!res.ok) throw new Error("Failed to send");
      if (!res.body) throw new Error("No body");

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let accumulated = "";
      let messageContent = "";
      let contextBlockConsumed = false;
      let overlayContext: RelevantContext | null = null;
      let didFireVisibleHaptic = false;

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        accumulated += decoder.decode(value, { stream: true });

        if (!contextBlockConsumed) {
          const parsed = parseRelevantContextFromStreamStart(accumulated);
          if (parsed.relevantContext !== null) {
            contextBlockConsumed = true;
            overlayContext = parsed.relevantContext;
            messageContent = parsed.contentWithoutBlock;
            accumulated = parsed.contentWithoutBlock;
          }
        } else {
          messageContent = accumulated;
        }

        setMessages((prev) => {
          const next = [...prev];
          const last = next[next.length - 1];
          if (last?.role === "assistant") {
            next[next.length - 1] = { ...last, content: contextBlockConsumed ? messageContent : "" };
          }
          return next;
        });
        const visibleContent = contextBlockConsumed ? messageContent : "";
        if (!didFireVisibleHaptic && visibleContent.trim().length > 0) {
          didFireVisibleHaptic = true;
          void playLlmResponseVisibleHaptic();
        }
      }

      const { contentWithoutBlock: afterCtx, relevantContext } = contextBlockConsumed
        ? { contentWithoutBlock: messageContent, relevantContext: overlayContext ?? undefined }
        : parseRelevantContextBlock(accumulated);
      const { contentWithoutBlock: afterMentor, mentorResponses } =
        parseMentorResponsesBlock(afterCtx);
      const { contentWithoutBlock: contentWithoutJournal } =
        parseJournalCheckpointBlock(afterMentor);
      const { contentWithoutBlock: contentWithoutQuestions, questions: parsedQuestions } =
        parseQuestionsBlock(contentWithoutJournal);
      const contentWithoutBlock = contentWithoutQuestions;
      const resolvedContext =
        relevantContext ??
        (() => {
          const extractedIds = extractMentalModelIds(contentWithoutBlock);
          return {
            mentalModels: extractedIds.map((id) => ({ id, reason: "" })),
            longTermMemories: [] as RelevantContextItem[],
            customConcepts: [] as RelevantContextItem[],
            conceptGroups: [] as RelevantContextItem[],
            perspectiveCards: [] as RelevantContextItem[],
          };
        })();
      setMessages((prev) => {
        const next = [...prev];
        const lastAssistantIdx = next.findLastIndex(
          (m) => m.role === "assistant"
        );
        if (lastAssistantIdx >= 0) {
          next[lastAssistantIdx] = {
            ...next[lastAssistantIdx],
            content: contentWithoutBlock,
            selectedContexts: {
              mentalModels: resolvedContext.mentalModels,
              longTermMemories: resolvedContext.longTermMemories,
              customConcepts: resolvedContext.customConcepts ?? [],
              conceptGroups: resolvedContext.conceptGroups ?? [],
              perspectiveCards: resolvedContext.perspectiveCards ?? [],
            },
            mentorResponses: mentorResponses ?? undefined,
            questions: parsedQuestions ?? undefined,
          };
        }
        return next;
      });
      if (!didFireVisibleHaptic && contentWithoutBlock.trim().length > 0) {
        didFireVisibleHaptic = true;
        void playLlmResponseVisibleHaptic();
      }
    } catch (err) {
      setLastFailedUserMessage(rawText);
      setMessages((prev) => {
        const next = [...prev];
        const last = next[next.length - 1];
        if (last?.role === "assistant") {
          next[next.length - 1] = {
            ...last,
            content: "Something went wrong.",
          };
        }
        return next;
      });
    } finally {
      // Don't navigate when creating a session from carousel - router.replace and
      // history.replaceState were causing the page to reset to the empty state.
      // We stay on /chat/new; the session appears in the sidebar for the user to click.
      setIsLoading(false);
      inputRef.current?.focus();
      refetchSessions();
      refetchScore();
    }
  }, [isLoading, currentSessionId, router, refetchSessions, refetchScore, messages, messages.length, sessions.length, dismissOnboarding, mentalModelsIndex, longTermMemories, customConcepts, conceptGroups, isAnonymous, incognitoMode, pendingCardContext, pendingOneOnOneMentor, pendingSecondOrder, multiMentorMode, selectedMentorFigureIds, replaceComposerInput]);

