  const landingWeightWeekPoints = useMemo(() => {
    const now = Date.now();
    const weekMs = 7 * 24 * 60 * 60 * 1000;
    return weightTrackerEntries
      .filter((e) => {
        const ts = new Date(e.recordedAt || e.createdAt).getTime();
        return Number.isFinite(ts) && now - ts <= weekMs;
      })
      .sort(
        (a, b) =>
          new Date(a.recordedAt || a.createdAt).getTime() -
          new Date(b.recordedAt || b.createdAt).getTime()
      )
      .map((e) => ({
        dateLabel: new Intl.DateTimeFormat(language, { weekday: "short", day: "numeric" }).format(
          new Date(e.recordedAt || e.createdAt)
        ),
        weightKg: e.weightKg,
      }));
  }, [weightTrackerEntries, language]);

  const weightTrackerFilteredChronological = useMemo(() => {
    const now = Date.now();
    const rangeMs =
      weightTrackerRange === "week"
        ? 7 * 24 * 60 * 60 * 1000
        : weightTrackerRange === "month"
          ? 30 * 24 * 60 * 60 * 1000
          : 365 * 24 * 60 * 60 * 1000;
    const filtered = weightTrackerEntries.filter((entry) => {
      const ts = new Date(entry.recordedAt || entry.createdAt).getTime();
      return Number.isFinite(ts) && now - ts <= rangeMs;
    });
    return filtered
      .slice()
      .sort(
        (a, b) =>
          new Date(a.recordedAt || a.createdAt).getTime() - new Date(b.recordedAt || b.createdAt).getTime()
      );
  }, [weightTrackerEntries, weightTrackerRange]);

