      if (e.metaKey || e.ctrlKey || e.shiftKey || e.altKey || e.button !== 0) return;
      e.preventDefault();
      closeAllModalsExceptLeftPanel();
      if (typeof window !== "undefined" && window.innerWidth < 1024) setSidebarOpen(false);
      setBrandLogoParty(true);
