            try {
              localStorage.setItem(FEATURE_TOUR_COMPLETE_KEY, "true");
            } catch {
              /* ignore */
            }
            setFeatureTourStep(null);
            setLibraryPanelOpen(null);
            setSelectedMentalModel(null);
